+        "application/json": {
+          schema: BeadResponseSchema,
+        },
+      },
+    },
+    404: {
+      description: "Bead not found",
+      content: {
+        "application/json": {
+          schema: ApiErrorResponseSchema,
+        },
+      },
+    },
+  },
+});
+
+registry.registerPath({
+  method: "post",
+  path: "/beads/{id}/claim",
